function createClient(url2) {
  const client = src_default(url2, { max: 10 });
  return drizzle(client, { schema: exports_schema });
}
var db;
function getDb(url2) {
  if (!db) {
    const connectionUrl = url2 ?? process.env.DATABASE_URL;
    if (!connectionUrl) {
      throw new Error("DATABASE_URL is required");
    }
    db = createClient(connectionUrl);
  }
  return db;
}
