var listQuerySchema = exports_external.object({
  page: exports_external.coerce.number().int().positive().default(1),
  pageSize: exports_external.coerce.number().int().positive().max(100).default(20)
});
var activityRoute = new Hono2;
activityRoute.get("/project/:projectId", async (c) => {
  const projectId = c.req.param("projectId");
  const parsed = listQuerySchema.safeParse(c.req.query());
  if (!parsed.success) {
    throw new AppError("VALIDATION_ERROR", "Invalid query parameters", {
      issues: parsed.error.flatten().fieldErrors
    });
  }
  const { page, pageSize } = parsed.data;
  const offset = (page - 1) * pageSize;
  const db2 = getDb();
  const [items, countResult] = await Promise.all([
    db2.select().from(projectActivities).where(eq(projectActivities.projectId, projectId)).orderBy(desc(projectActivities.createdAt)).limit(pageSize).offset(offset),
    db2.select({ count: sql`count(*)::int` }).from(projectActivities).where(eq(projectActivities.projectId, projectId))
  ]);
  return c.json({
    success: true,
    data: {
      items,
      total: countResult[0]?.count ?? 0,
      page,
      pageSize
    }
  });
});

