var MILESTONE_TRANSITIONS = {
  pending: ["in_progress"],
  in_progress: ["submitted"],
  submitted: ["approved", "revision_requested", "rejected"],
  revision_requested: ["in_progress"],
  approved: [],
  rejected: []
};

class MilestoneService {
  milestoneRepo;
  projectRepo;
  constructor(milestoneRepo, projectRepo) {
    this.milestoneRepo = milestoneRepo;
    this.projectRepo = projectRepo;
  }
  async listByProject(projectId) {
    const project2 = await this.projectRepo.findById(projectId);
    if (!project2) {
      throw new AppError("PROJECT_NOT_FOUND", "Project not found");
    }
    return await this.milestoneRepo.findByProjectId(projectId);
  }
  async getMilestone(id) {
    const milestone = await this.milestoneRepo.findById(id);
    if (!milestone) {
      throw new AppError("MILESTONE_NOT_FOUND", "Milestone not found");
    }
    return milestone;
  }
  async createMilestone(input) {
    const project2 = await this.projectRepo.findById(input.projectId);
    if (!project2) {
      throw new AppError("PROJECT_NOT_FOUND", "Project not found");
    }
    return await this.milestoneRepo.create({
      projectId: input.projectId,
      workPackageId: input.workPackageId ?? null,
      assignedWorkerId: input.assignedWorkerId ?? null,
      title: input.title,
      description: input.description,
      milestoneType: input.milestoneType ?? "individual",
      orderIndex: input.orderIndex,
      amount: input.amount,
      status: "pending",
      revisionCount: 0,
      dueDate: new Date(input.dueDate),
      metadata: input.metadata ?? null
    });
  }
  async updateMilestoneStatus(id, newStatus) {
    const milestone = await this.milestoneRepo.findById(id);
    if (!milestone) {
      throw new AppError("MILESTONE_NOT_FOUND", "Milestone not found");
    }
    const currentStatus = milestone.status;
    const validTargets = MILESTONE_TRANSITIONS[currentStatus];
    if (!validTargets?.includes(newStatus)) {
      throw new AppError("MILESTONE_INVALID_STATUS", `Cannot transition milestone from '${currentStatus}' to '${newStatus}'. Valid targets: ${validTargets?.join(", ") || "none"}`);
    }
    if (newStatus === "revision_requested") {
      if (milestone.revisionCount >= FREE_REVISION_ROUNDS) {
        throw new AppError("MILESTONE_REVISION_LIMIT", `Free revision limit (${FREE_REVISION_ROUNDS}) reached. Additional revisions require payment.`);
      }
      return await this.milestoneRepo.incrementRevisionCount(id);
    }
    return await this.milestoneRepo.updateStatus(id, newStatus);
  }
}

