class TimeLogRepository {
  db;
  constructor(db2) {
    this.db = db2;
  }
  async findByTaskId(taskId) {
    return await this.db.select().from(timeLogs).where(eq(timeLogs.taskId, taskId)).orderBy(desc(timeLogs.startedAt));
  }
  async findByWorkerId(workerId) {
    return await this.db.select().from(timeLogs).where(eq(timeLogs.workerId, workerId)).orderBy(desc(timeLogs.startedAt));
  }
  async findById(id) {
    const result = await this.db.select().from(timeLogs).where(eq(timeLogs.id, id)).limit(1);
    return result[0];
  }
  async create(data) {
    const id = uuidv7();
    const result = await this.db.insert(timeLogs).values({
      id,
      taskId: data.taskId,
      workerId: data.workerId,
      startedAt: data.startedAt,
      endedAt: data.endedAt ?? null,
      durationMinutes: data.durationMinutes ?? null,
      description: data.description ?? null
    }).returning();
    if (!result[0])
      throw new AppError("INTERNAL_ERROR", "Time log insert failed");
    return result[0];
  }
  async stopTimer(id, endedAt, durationMinutes) {
    const result = await this.db.update(timeLogs).set({ endedAt, durationMinutes }).where(eq(timeLogs.id, id)).returning();
    return result[0];
  }
}

// src/services/time-log.service.ts
class TimeLogService {
  timeLogRepo;
  constructor(timeLogRepo) {
    this.timeLogRepo = timeLogRepo;
  }
  async createTimeLog(input) {
    const startedAt = new Date(input.startedAt);
    const endedAt = input.endedAt ? new Date(input.endedAt) : null;
    let durationMinutes = input.durationMinutes ?? null;
    if (endedAt && durationMinutes === null) {
      durationMinutes = Math.round((endedAt.getTime() - startedAt.getTime()) / 60000);
    }
    if (endedAt && endedAt <= startedAt) {
      throw new AppError("VALIDATION_ERROR", "endedAt must be after startedAt");
    }
    return await this.timeLogRepo.create({
      taskId: input.taskId,
      workerId: input.workerId,
      startedAt,
      endedAt,
      durationMinutes,
      description: input.description ?? null
    });
  }
  async getByTask(taskId) {
    return await this.timeLogRepo.findByTaskId(taskId);
  }
  async getByWorker(workerId) {
    return await this.timeLogRepo.findByWorkerId(workerId);
  }
  async stopTimer(id) {
    const log2 = await this.timeLogRepo.findById(id);
    if (!log2) {
      throw new AppError("NOT_FOUND", "Time log not found");
    }
    if (log2.endedAt) {
      throw new AppError("CONFLICT", "Timer is already stopped");
    }
    const endedAt = new Date;
    const durationMinutes = Math.round((endedAt.getTime() - log2.startedAt.getTime()) / 60000);
    return await this.timeLogRepo.stopTimer(id, endedAt, durationMinutes);
  }
}

