// src/repositories/work-package.repository.ts
class WorkPackageRepository {
  db;
  constructor(db2) {
    this.db = db2;
  }
  async findByProjectId(projectId) {
    return await this.db.select().from(workPackages).where(eq(workPackages.projectId, projectId)).orderBy(workPackages.orderIndex);
  }
  async findById(id) {
    const result = await this.db.select().from(workPackages).where(eq(workPackages.id, id)).limit(1);
    return result[0];
  }
  async create(data) {
    const id = uuidv7();
    const now = new Date;
    const result = await this.db.insert(workPackages).values({
      id,
      projectId: data.projectId,
      title: data.title,
      description: data.description,
      requiredSkills: data.requiredSkills,
      estimatedHours: data.estimatedHours,
      amount: data.amount,
      workerPayout: data.workerPayout,
      orderIndex: data.orderIndex,
      status: "unassigned",
      createdAt: now,
      updatedAt: now
    }).returning();
    if (!result[0])
      throw new AppError("INTERNAL_ERROR", "Work package insert failed");
    return result[0];
  }
  async createMany(inputs) {
    if (inputs.length === 0)
      return [];
    const now = new Date;
    const values2 = inputs.map((data) => ({
      id: uuidv7(),
      projectId: data.projectId,
      title: data.title,
      description: data.description,
      requiredSkills: data.requiredSkills,
      estimatedHours: data.estimatedHours,
      amount: data.amount,
      workerPayout: data.workerPayout,
      orderIndex: data.orderIndex,
      status: "unassigned",
      createdAt: now,
      updatedAt: now
    }));
    return await this.db.insert(workPackages).values(values2).returning();
  }
  async updateStatus(id, status) {
    const result = await this.db.update(workPackages).set({ status, updatedAt: new Date }).where(eq(workPackages.id, id)).returning();
    return result[0];
  }
  async getDependencies(workPackageId) {
    return await this.db.select().from(workPackageDependencies).where(eq(workPackageDependencies.workPackageId, workPackageId));
  }
  async getDependenciesByProject(projectId) {
    const packages = await this.findByProjectId(projectId);
    const packageIds = packages.map((p) => p.id);
    if (packageIds.length === 0)
      return [];
    return await this.db.select().from(workPackageDependencies).where(inArray(workPackageDependencies.workPackageId, packageIds));
  }
  async createDependency(data) {
    const result = await this.db.insert(workPackageDependencies).values({
      id: uuidv7(),
      workPackageId: data.workPackageId,
      dependsOnWorkPackageId: data.dependsOnWorkPackageId,
      type: data.type ?? "finish_to_start"
    }).returning();
    if (!result[0])
      throw new AppError("INTERNAL_ERROR", "Work package dependency insert failed");
    return result[0];
  }
}

// src/services/work-package.service.ts
class WorkPackageService {
  workPackageRepo;
  projectRepo;
  constructor(workPackageRepo, projectRepo) {
    this.workPackageRepo = workPackageRepo;
    this.projectRepo = projectRepo;
  }
  async listByProject(projectId) {
    const project2 = await this.projectRepo.findById(projectId);
    if (!project2) {
      throw new AppError("PROJECT_NOT_FOUND", "Project not found");
    }
    return await this.workPackageRepo.findByProjectId(projectId);
  }
  async getWorkPackage(id) {
    const wp = await this.workPackageRepo.findById(id);
    if (!wp) {
      throw new AppError("NOT_FOUND", "Work package not found");
    }
    return wp;
  }
  async createWorkPackages(projectId, packages) {
    const project2 = await this.projectRepo.findById(projectId);
    if (!project2) {
      throw new AppError("PROJECT_NOT_FOUND", "Project not found");
    }
    const inputs = packages.map((pkg) => ({
      projectId,
      title: pkg.title,
      description: pkg.description,
      requiredSkills: pkg.requiredSkills,
      estimatedHours: pkg.estimatedHours,
      amount: pkg.amount,
      workerPayout: pkg.workerPayout,
      orderIndex: pkg.orderIndex
    }));
    return await this.workPackageRepo.createMany(inputs);
  }
  async updateStatus(id, status) {
    const wp = await this.workPackageRepo.findById(id);
    if (!wp) {
      throw new AppError("NOT_FOUND", "Work package not found");
    }
    return await this.workPackageRepo.updateStatus(id, status);
  }
  async addDependency(workPackageId, dependsOnWorkPackageId, type) {
    const wp = await this.workPackageRepo.findById(workPackageId);
    if (!wp) {
      throw new AppError("NOT_FOUND", "Work package not found");
    }
    const depWp = await this.workPackageRepo.findById(dependsOnWorkPackageId);
    if (!depWp) {
      throw new AppError("NOT_FOUND", "Dependency work package not found");
    }
    if (wp.projectId !== depWp.projectId) {
      throw new AppError("VALIDATION_ERROR", "Work packages must belong to the same project");
    }
    if (workPackageId === dependsOnWorkPackageId) {
      throw new AppError("VALIDATION_ERROR", "Work package cannot depend on itself");
    }
    return await this.workPackageRepo.createDependency({
      workPackageId,
      dependsOnWorkPackageId,
      type
    });
  }
  async getDependencies(projectId) {
    const project2 = await this.projectRepo.findById(projectId);
    if (!project2) {
      throw new AppError("PROJECT_NOT_FOUND", "Project not found");
    }
    return await this.workPackageRepo.getDependenciesByProject(projectId);
  }
}

