// src/routes/worker-profiles.ts
var proficiencyValues = ["beginner", "intermediate", "advanced", "expert"];
var availabilityValues = ["available", "busy", "unavailable"];
var createProfileSchema = exports_external.object({
  userId: exports_external.string(),
  bio: exports_external.string().max(2000).optional(),
  yearsOfExperience: exports_external.number().int().nonnegative(),
  educationUniversity: exports_external.string().max(255).optional(),
  educationMajor: exports_external.string().max(255).optional(),
  educationYear: exports_external.number().int().optional(),
  skills: exports_external.array(exports_external.object({
    name: exports_external.string(),
    proficiencyLevel: exports_external.enum(proficiencyValues),
    isPrimary: exports_external.boolean().default(false)
  })).optional(),
  portfolioLinks: exports_external.array(exports_external.object({ platform: exports_external.string(), url: exports_external.string() })).optional(),
  domainExpertise: exports_external.array(exports_external.string()).optional()
});
var updateAvailabilitySchema = exports_external.object({
  availability: exports_external.enum(availabilityValues)
});
var workerProfileRoute = new Hono2;
workerProfileRoute.post("/", async (c) => {
  const body = await c.req.json();
  const parsed = createProfileSchema.safeParse(body);
  if (!parsed.success) {
    throw new AppError("VALIDATION_ERROR", "Invalid profile data", {
      issues: parsed.error.flatten().fieldErrors
    });
  }
  const db2 = getDb();
  const data = parsed.data;
  const [existing] = await db2.select({ id: workerProfiles.id }).from(workerProfiles).where(eq(workerProfiles.userId, data.userId)).limit(1);
  let profileId;
  if (existing) {
    await db2.update(workerProfiles).set({
      bio: data.bio,
      yearsOfExperience: data.yearsOfExperience,
      educationUniversity: data.educationUniversity,
      educationMajor: data.educationMajor,
      educationYear: data.educationYear,
      portfolioLinks: data.portfolioLinks,
      domainExpertise: data.domainExpertise,
      verificationStatus: "verified",
      updatedAt: new Date
    }).where(eq(workerProfiles.id, existing.id));
    profileId = existing.id;
  } else {
    profileId = uuidv7();
    await db2.insert(workerProfiles).values({
      id: profileId,
      userId: data.userId,
      bio: data.bio,
      yearsOfExperience: data.yearsOfExperience,
      educationUniversity: data.educationUniversity,
      educationMajor: data.educationMajor,
      educationYear: data.educationYear,
      portfolioLinks: data.portfolioLinks,
      domainExpertise: data.domainExpertise,
      verificationStatus: "verified"
    });
  }
  if (data.skills?.length) {
    await db2.delete(workerSkills).where(eq(workerSkills.workerId, profileId));
    for (const s of data.skills) {
      const [skill] = await db2.select({ id: skills.id }).from(skills).where(eq(skills.name, s.name)).limit(1);
      if (skill) {
        await db2.insert(workerSkills).values({
          workerId: profileId,
          skillId: skill.id,
          proficiencyLevel: s.proficiencyLevel,
          isPrimary: s.isPrimary
        }).onConflictDoNothing();
      }
    }
  }
  return c.json({ success: true, data: { profileId } }, 201);
});
workerProfileRoute.get("/user/:userId", async (c) => {
  const userId = c.req.param("userId");
  const db2 = getDb();
  const [profile] = await db2.select().from(workerProfiles).where(eq(workerProfiles.userId, userId)).limit(1);
  if (!profile) {
    throw new AppError("NOT_FOUND", "Worker profile not found");
  }
  return c.json({ success: true, data: profile });
});
workerProfileRoute.patch("/:id/availability", async (c) => {
  const id = c.req.param("id");
  const body = await c.req.json();
  const parsed = updateAvailabilitySchema.safeParse(body);
  if (!parsed.success) {
    throw new AppError("VALIDATION_ERROR", "Invalid availability", {
      issues: parsed.error.flatten().fieldErrors
    });
  }
  const db2 = getDb();
  const [updated] = await db2.update(workerProfiles).set({
    availabilityStatus: parsed.data.availability,
    updatedAt: new Date
  }).where(eq(workerProfiles.id, id)).returning();
  if (!updated) {
    throw new AppError("NOT_FOUND", "Profile not found");
  }
  return c.json({ success: true, data: updated });
});

// src/routes/workers.ts
var availabilityValues2 = ["available", "busy", "unavailable"];
var listWorkersQuerySchema = exports_external.object({
  skill: exports_external.string().optional(),
  availability: exports_external.enum(availabilityValues2).optional(),
  page: exports_external.coerce.number().int().positive().default(1),
  pageSize: exports_external.coerce.number().int().positive().max(100).default(20)
});
var workerRoute = new Hono2;
workerRoute.get("/", async (c) => {
  const parsed = listWorkersQuerySchema.safeParse(c.req.query());
  if (!parsed.success) {
    throw new AppError("VALIDATION_ERROR", "Invalid query parameters", {
      issues: parsed.error.flatten().fieldErrors
    });
  }
  const { skill, availability, page, pageSize } = parsed.data;
  const db2 = getDb();
  const offset = (page - 1) * pageSize;
  const conditions = [];
  if (availability) {
    conditions.push(eq(workerProfiles.availabilityStatus, availability));
  }
  conditions.push(eq(workerProfiles.verificationStatus, "verified"));
  let query = db2.select({
    id: workerProfiles.id,
    userId: workerProfiles.userId,
    bio: workerProfiles.bio,
    yearsOfExperience: workerProfiles.yearsOfExperience,
    availabilityStatus: workerProfiles.availabilityStatus,
    verificationStatus: workerProfiles.verificationStatus,
    domainExpertise: workerProfiles.domainExpertise,
    totalProjectsCompleted: workerProfiles.totalProjectsCompleted,
    totalProjectsActive: workerProfiles.totalProjectsActive,
    portfolioLinks: workerProfiles.portfolioLinks,
    createdAt: workerProfiles.createdAt
  }).from(workerProfiles).$dynamic();
  if (skill) {
    query = query.innerJoin(workerSkills, eq(workerSkills.workerId, workerProfiles.id)).innerJoin(skills, eq(skills.id, workerSkills.skillId)).where(and(...conditions, eq(skills.name, skill)));
  } else {
    query = query.where(conditions.length > 0 ? and(...conditions) : undefined);
  }
  const workers = await query.limit(pageSize).offset(offset);
  const countResult = await db2.select({ id: workerProfiles.id }).from(workerProfiles).where(eq(workerProfiles.verificationStatus, "verified"));
  return c.json({
    success: true,
    data: {
      items: workers,
      total: countResult.length,
      page,
      pageSize
    }
  });
});
workerRoute.get("/:id", async (c) => {
  const id = c.req.param("id");
  const db2 = getDb();
  const [worker] = await db2.select({
    id: workerProfiles.id,
    bio: workerProfiles.bio,
    yearsOfExperience: workerProfiles.yearsOfExperience,
    educationUniversity: workerProfiles.educationUniversity,
    educationMajor: workerProfiles.educationMajor,
    availabilityStatus: workerProfiles.availabilityStatus,
    verificationStatus: workerProfiles.verificationStatus,
    domainExpertise: workerProfiles.domainExpertise,
    totalProjectsCompleted: workerProfiles.totalProjectsCompleted,
    totalProjectsActive: workerProfiles.totalProjectsActive,
    portfolioLinks: workerProfiles.portfolioLinks,
    createdAt: workerProfiles.createdAt
  }).from(workerProfiles).where(eq(workerProfiles.id, id)).limit(1);
  if (!worker) {
    throw new AppError("WORKER_NOT_FOUND", "Worker not found");
  }
  return c.json({
    success: true,
    data: worker
  });
});
workerRoute.get("/:id/skills", async (c) => {
  const id = c.req.param("id");
  const db2 = getDb();
  const [worker] = await db2.select({ id: workerProfiles.id }).from(workerProfiles).where(eq(workerProfiles.id, id)).limit(1);
  if (!worker) {
    throw new AppError("WORKER_NOT_FOUND", "Worker not found");
  }
  const workerSkillRows = await db2.select({
    skillId: workerSkills.skillId,
    proficiencyLevel: workerSkills.proficiencyLevel,
    isPrimary: workerSkills.isPrimary,
    skillName: skills.name,
    skillCategory: skills.category
  }).from(workerSkills).innerJoin(skills, eq(skills.id, workerSkills.skillId)).where(eq(workerSkills.workerId, id));
  return c.json({
    success: true,
    data: workerSkillRows
  });
});

